import{_ as a,c as s,o as i,U as e}from"./chunks/framework.9QHaLlVJ.js";const g=JSON.parse('{"title":"计算机基础","description":null,"frontmatter":{"lang":"zh-CN","title":"计算机基础","description":null},"headers":[],"relativePath":"doc/网络安全/XSS/XSS.md","filePath":"packages/doc/src/网络安全/XSS/XSS.md","lastUpdated":1704643216000}'),t={name:"doc/网络安全/XSS/XSS.md"},n=e(`<h1 id="xss" tabindex="-1">XSS <a class="header-anchor" href="#xss" aria-label="Permalink to &quot;XSS&quot;">​</a></h1><h2 id="_1-什么是xss" tabindex="-1">1.什么是XSS？ <a class="header-anchor" href="#_1-什么是xss" aria-label="Permalink to &quot;1.什么是XSS？&quot;">​</a></h2><p>听过很多道理，当然很多人都已经知道XSS是个啥，跨站脚本（Cross-Site Scripting），由于它前面有个老大哥CSS摆在那儿，就只能叫XSS了。官方是这么说的<a href="https://link.segmentfault.com/?enc=jJxf7VeoDG%2FaiVi2nDtPiw%3D%3D.h%2BRQKo20fApS1ipS%2FgAXQJExvNI7MR%2F6uWt9Y9q8wdtfYsNhSE1du48h3DZgCJ1L0u3Jtry1cc%2FcHBJkQm4Hqw%3D%3D" target="_blank" rel="noreferrer">&quot;A cross-site scripting vulnerability may be used by attackers to bypass access controls such as the same-origin policy.&quot;</a>“一种可能会被攻击者用来 通过 比如同源策略 来获取用户权限的跨站脚本。” 通俗点来说，比如你在浏览百度的时候，假设百度没做任何安全策略（当然这是不可能的），攻击者对百度的登陆按钮做了点修改，你登陆的时候，它把你登陆的信息都发送到攻击者那儿去了，GG，2个T的学习资料没了。这还算好的，给你的花旗银行网站来个这玩意，2个亿没了。</p><h2 id="_2-xss的分类" tabindex="-1">2.XSS的分类 <a class="header-anchor" href="#_2-xss的分类" aria-label="Permalink to &quot;2.XSS的分类&quot;">​</a></h2><h3 id="反射型xss" tabindex="-1">反射型XSS <a class="header-anchor" href="#反射型xss" aria-label="Permalink to &quot;反射型XSS&quot;">​</a></h3><p>也叫做非持久性、参数性跨站脚本，顾名思义，攻击者制作了一个含有恶意代码的url，比如</p><blockquote><p>(这个算恶意比较小的，要是在里面获取你的cookie</p></blockquote><p>然后攻击者给你发了个链接，“大胸妹妹正在直播，邀请您观看。”</p><p>大家可以搭个DVWA自己玩一下嘛，别的漏洞也有，就是别用太高级的浏览器，这时候深恶痛绝的IE就该上场了，时候表演真正的技术了。 “我不服，就这URL我还不一眼就看出来有毛病？” “http%3A//www.test.com/search.php%3Fkey%3D%22%3Cscript%3Ealert%28%22xss%22%29%3C/script%3E%22，继续装逼。”</p><h3 id="持久型xss" tabindex="-1">持久型XSS <a class="header-anchor" href="#持久型xss" aria-label="Permalink to &quot;持久型XSS&quot;">​</a></h3><p>相当于存储型跨站脚本。 当然了这不是你的锅，但如果这个网站是你搭的，那你等着GG吧。如果这个玩意儿一直没有被搞掉，而攻击者给你来了10000个这样的评论，每一次刷新后都会来10000下，想想会发生什么吧。</p><h2 id="xss构造剖析" tabindex="-1">XSS构造剖析 <a class="header-anchor" href="#xss构造剖析" aria-label="Permalink to &quot;XSS构造剖析&quot;">​</a></h2><h3 id="绕过xss-filter" tabindex="-1">绕过XSS-Filter <a class="header-anchor" href="#绕过xss-filter" aria-label="Permalink to &quot;绕过XSS-Filter&quot;">​</a></h3><p>我们有很多绕过Filter的方法：</p><h4 id="_1-利用-标记注射代码" tabindex="-1">1)利用&lt;&gt;标记注射代码 <a class="header-anchor" href="#_1-利用-标记注射代码" aria-label="Permalink to &quot;1)利用&lt;&gt;标记注射代码&quot;">​</a></h4><p>前面我们写的大胸妹，哦不是，代码都是这样的，不多说了。</p><h4 id="_2-利用html标签属性执行xss" tabindex="-1">2)利用HTML标签属性执行XSS <a class="header-anchor" href="#_2-利用html标签属性执行xss" aria-label="Permalink to &quot;2)利用HTML标签属性执行XSS&quot;">​</a></h4><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>&lt;table background=&quot;javascript:alert(/XSS/)&quot;&gt;&lt;/table&gt;</span></span>
<span class="line"><span>&lt;img src=&quot;javascript:alert(&#39;XSS&#39;)&quot;&gt;;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这玩意儿呢对我们这些使用Canary、Nighty的人来说是没有任何威胁的?，当然对一些非功能需要还在使用IE6的山顶洞人还是有点威胁的。</p><h4 id="_3-空格回车tab" tabindex="-1">3)空格回车Tab <a class="header-anchor" href="#_3-空格回车tab" aria-label="Permalink to &quot;3)空格回车Tab&quot;">​</a></h4><p>加入你在你的黑名单里加了&#39;javascript&#39;，然后说这下没办法来写脚本了吧。对不起，没用。 <code>&lt;img src=&quot;java script:alert(&#39;XSS&#39;)&quot;&gt;</code>再次GG。这玩意儿涉及到一点js和浏览器引擎解析的问题。我们知道</p><div class="language-stylus vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">stylus</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">var</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;"> a</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> daxiongmei</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">var</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;"> b</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;kan na ge daxiongmei&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这样虽然没有分号不像我们这些规范的程序员的编程习惯，但它是没毛病的而且很Geek，那这样呢？</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>var a </span></span>
<span class="line"><span>= &#39;kan na ge daxiongmei;</span></span>
<span class="line"><span>alert(a);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>也是可以的！因为引擎并不会把换行符看成一个完整语句的终点（上面的可以是因为引擎已经意识到一个完整的语句了），它会继续处理后面发现的内容，知道一个分号出现或者这个语句变成一个完整的语句。</p><h4 id="_4-对标签属性值转码" tabindex="-1">4)对标签属性值转码 <a class="header-anchor" href="#_4-对标签属性值转码" aria-label="Permalink to &quot;4)对标签属性值转码&quot;">​</a></h4><p>那我处理输入的时候<code>.split(&quot; &quot;).join(&quot;&quot;)</code>行了吧，对不起还是不行。 还记得大写字母A的ASCII码是多少吗，不记得先向你的老师说声对不起又还给您了。 说正事，HTML是支持ASCII码形式的。我们把上面的代码换成这样。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>&lt;img src=&quot;javascrip&amp;#116&amp;#58alert(&quot;XSS&quot;)&gt;;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>GG</strong> 所以最好把这些字符也给过滤了吧。</p><h4 id="_5-产生自己的事件" tabindex="-1">5)产生自己的事件 <a class="header-anchor" href="#_5-产生自己的事件" aria-label="Permalink to &quot;5)产生自己的事件&quot;">​</a></h4><p>这个和上面的第二点有点类似，只不过这次把属性换成事件，像这样：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>&lt;img src=&quot;#&quot; onerror=alert(/xss/)&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><code>onerror</code>换成<code>onclick</code>,<code>onblur</code>什么都是可以的。</p><h4 id="_6-利用css跨站" tabindex="-1">6)利用CSS跨站 <a class="header-anchor" href="#_6-利用css跨站" aria-label="Permalink to &quot;6)利用CSS跨站&quot;">​</a></h4><p>CSS也可以用来跨站，想的起来是什么吗？方式还挺多的</p><div class="language-applescript vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">applescript</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;div</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> style</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;backgroun-image:url(javascript:alert(&#39;XSS&#39;))&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;&lt;/div&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>或者用@important引入，引入文件写个xss，就是这么简单。你说我们名字简写都一样的，相煎何太急呢。</p><h3 id="利用字符串编码" tabindex="-1">利用字符串编码 <a class="header-anchor" href="#利用字符串编码" aria-label="Permalink to &quot;利用字符串编码&quot;">​</a></h3><p>其实之前我们已经几次提到了用字符串编码来绕过Filter的方法，由于js支持Unicode、escapes、十六进制、八进制等编码，还有很多加密编码，防止XSS变得很麻烦，心累。</p><h3 id="拆分跨站法" tabindex="-1">拆分跨站法 <a class="header-anchor" href="#拆分跨站法" aria-label="Permalink to &quot;拆分跨站法&quot;">​</a></h3><p>可能有的同学要想好事儿了，你每次攻击我都要写那么长的代码，我限制你个字符输入字数为比如30个不就行了吗，你写两个script标签都要17个字符了。Naive</p><div class="language-xml vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;z=&#39;document.&#39;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;z=z+&#39;write(&#39;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">...</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;eval(z)&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><strong>GG</strong></p><h2 id="shellcode的调用" tabindex="-1">Shellcode的调用 <a class="header-anchor" href="#shellcode的调用" aria-label="Permalink to &quot;Shellcode的调用&quot;">​</a></h2><p>有几个概念我们先来了解一下。 【Shellcode】 这玩意儿呢一开始是指溢出程序和蠕虫病毒的核心，其实看单词就能看出来了，就是一个利用漏洞执行时的代码。在咱么这儿呢，就是指XSS利用代码。 【Exploit】 翻译：利用。这玩意我我不知道怎么解释，“通常表示完整编写好的漏洞利用工具”，总之记住Exploit往往包含了Shellcode。 <a href="https://link.segmentfault.com/?enc=YkWmcBDZYsTK4V%2BhN%2FhLUA%3D%3D.mSqimKgIdAer1MJmQ2GyP4zbYtUoOrMg4Hb%2FXH1r414eu7w%2Bc0ZFNVkzGihl%2BF1WuiJQuDZdaRKKUn0JfoDwydYlbCDEAkBrsk%2Bj69g5SnN2uEbKG82F%2BJuacdy1KFR7AgRD9WVWK1hJlvnke5NFmY1oEgChWG%2BjKHeH6PbEDdovijpUzEiTtwLvOaRvgvFD%2F4SnqfiaCRbLv3cE7lfBGg%2Fg2E6m8PUzGpsrNS%2FheMw%3D" target="_blank" rel="noreferrer">payload、shellcode、exp、poc怎么区别?</a> 【POC】 Proof of Concept，是一段证明漏洞存在的程序代码片段。</p><h3 id="动态调用远程javascript" tabindex="-1">动态调用远程JavaScript <a class="header-anchor" href="#动态调用远程javascript" aria-label="Permalink to &quot;动态调用远程JavaScript&quot;">​</a></h3><p>其实这和JSONP有点类似，在url后面跟个script标签，标签里引入远程的js文件，这文件不是个好东西，恩差不多就是这样。</p><h3 id="使用window-location-hash" tabindex="-1">使用window.location.hash <a class="header-anchor" href="#使用window-location-hash" aria-label="Permalink to &quot;使用window.location.hash&quot;">​</a></h3><p>知道location.hash获取什么吗？比如我们有个url：<a href="https://link.segmentfault.com/?enc=MeIZZdY1uqOyfvX0YKz%2BFw%3D%3D.4khV%2FXLuNcBoDHHAk0ETuSZ%2FUtSzRWx4m6Hh8Qtoa%2BU%3D" target="_blank" rel="noreferrer">http://domain/#admin,</a> location.hash获取的就是&#39;#&#39;后面的东西，这里就是admin。那location.hash怎么用到我们的XSS里面呢？</p><div class="language-awk vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">awk</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">http</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">://</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">www.bug.com</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">veiw.php</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">?</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sort</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&gt;&lt;script&gt;eval(location.hash.substr(1))&lt;/script&gt;#alert(&#39;xss&#39;)&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>应该都能看懂我就不多说了啊。</p><h3 id="xss-downloader" tabindex="-1">XSS Downloader <a class="header-anchor" href="#xss-downloader" aria-label="Permalink to &quot;XSS Downloader&quot;">​</a></h3><p>介绍另外一种存储和调用Shellcode的方法，把它存储到网站的数据库中个，然后再把它下载下来执行。简单说呢，就是我们写了个XSS的下载器，把这个下载器放在网站的某个页面，再用Ajax什么的来向这个网站发送请求，执行了返回的数据，返回的是啥？Shellcode。</p><h3 id="备选存储技术" tabindex="-1">备选存储技术 <a class="header-anchor" href="#备选存储技术" aria-label="Permalink to &quot;备选存储技术&quot;">​</a></h3><p>浏览器的存储技术有哪些？相信经过校招的同学都应该不陌生。Cookie、Flash、UserData、localStorage等。既然这些玩意儿都能存储数据，那Shellcode呢，当然也可以。</p>`,55),l=[n];function r(p,h,o,d,c,k){return i(),s("div",null,l)}const b=a(t,[["render",r]]);export{g as __pageData,b as default};
